SELECT e.employeeid, e.firstname, e.lastname, o.orderid, o.shippeddate, od.quantity, od.unitprice FROM employees e JOIN orders o ON e.employeeid = o.employeeid JOIN "order details" od ON o.orderid = od.orderid JOIN employeeterritories et ON e.employeeid = et.employeeid JOIN territories t ON et.territoryid = t.territoryid WHERE (t.regionid = 2) AND (strftime('%Y', o.shippeddate) = '1997')
